func DecodeNamespace[S, C any](configSource any, buildConfig func(any) (C, any, error)) (*ConfigNamespace[S, C], error) {

	h := hashing.HashString(configSource)

	c, ext, err := buildConfig(configSource)
	if err != nil {
		return nil, err
	}

	if ext == nil {
		ext = configSource
	}

	if ext == nil {
		panic("ext is nil")
	}

	ns := &ConfigNamespace[S, C]{
		SourceStructure:	ext,
		SourceHash:		h,
		Config:			c,
	}

	return ns, nil
}
